class BaseHashTable:

  def __init__(self, size=13):
    self.size = size              # 테이블 크기
    self.count = 0                # 현재 저장된 데이터 개수
    self.table = [None] * size    # 해시 테이블 초기화


  def load_factor(self):
    return (self.count + 1) / self.size  # 적재율 (rehash 판단 기준) (rehash if문이 count하는 함수보다 )


  def rehash(self):
    old_table = self.table        # 기존 테이블 백업

    self.size *= 2                # 테이블 크기 2배 확장 (핵심)
    self.table = [None] * self.size
    self.count = 0                # 다시 삽입할 것이므로 count 초기화

    # 기존 데이터들을 새로운 테이블에 재삽입
    for item in old_table:

      if item is None:
        continue                  # 비어있는 슬롯은 무시

      # Chaining (list 형태) 처리
      if isinstance(item, list):
        for k, v in item:
          self.insert(k, v)       # 새 해시값으로 다시 삽입

      # Open Addressing (tuple 형태) 처리
      elif isinstance(item, tuple):
        self.insert(item[0], item[1])

      # Linked List (Chaining) 처리
      else:
        cur = item
        while cur:
          self.insert(cur.key, cur.value)  # 연결된 노드 모두 재삽입
          cur = cur.next

class NFoldingHashTable(BaseHashTable):

  def __init__(self, size, fold_size):
    super().__init__(size)
    self.fold_size = fold_size   # 접는 자릿수


  def hash_fn(self, key):
    key = str(key)
    total = 0

    # fold_size 만큼 끊기
    for i in range(0, len(key), self.fold_size):
      total += int(key[i:i+self.fold_size])

    return total % self.size


  def insert(self, key, value):

    if self.load_factor() > 0.7:
      self.rehash()

    idx = self.hash_fn(key)
    start = idx

    while self.table[idx] is not None:
      idx = (idx + 1) % self.size

      if idx == start:
        print("insert FAIL: table is full")
        return

    self.table[idx] = (key, value)
    self.count += 1


  def search(self, key):

    idx = self.hash_fn(key)
    start = idx

    while self.table[idx] is not None:

      if self.table[idx][0] == key:
        return self.table[idx][1]

      idx = (idx + 1) % self.size

      if idx == start:
        break

    return None


  def delete(self, key):

    idx = self.hash_fn(key)
    start = idx

    while self.table[idx] is not None:

      if self.table[idx][0] == key:
        self.table[idx] = None
        self.count -= 1
        print(f"{key} deleted")
        return

      idx = (idx + 1) % self.size

      if idx == start:
        break

    print("delete FAIL: key not found")


  def display(self):
    print("\n[ 해시 테이블 상태 ]")
    for i, slot in enumerate(self.table):
      print(f"  [{i}] {slot}")
    print()

class ChainingHashTable(BaseHashTable):

  def hash_fn(self, key):
    return key % self.size


  def insert(self, key, value):

    if self.load_factor() > 0.7:
      self.rehash()

    idx = self.hash_fn(key)

    new = Node(key, value)

    if self.table[idx] is None:
      self.table[idx] = new
    else:
      cur = self.table[idx]
      new.next = cur # 기존에 while문을 통해 뒤에 붙이는 걸 앞에 붙이는 걸로 바꿈
      self.table[idx] = new

    self.count += 1


  def search(self, key):

    idx = self.hash_fn(key)
    cur = self.table[idx]

    while cur:
      if cur.key == key:
        return cur.value
      cur = cur.next

    return None


  def delete(self, key):

    idx = self.hash_fn(key)
    cur = self.table[idx]
    prev = None

    while cur:

      if cur.key == key:

        if prev is None:
          self.table[idx] = cur.next
        else:
          prev.next = cur.next

        self.count -= 1
        print(f"{key} deleted")
        return

      prev = cur
      cur = cur.next

    print("delete FAIL: key not found")


  def display(self):
    print("\n[ 해시 테이블 상태 ]")

    for i, slot in enumerate(self.table):

      print(f"[{i}]", end=" ")

      cur = slot
      if cur is None:
        print("None")
      else:
        while cur:
          print(f"({cur.key}, '{cur.value}')", end=" -> ")
          cur = cur.next
        print("None")

    print()

class BSTNode:
  def __init__(self, key, value):
