class BST:

  def insert(self, root, key, value):

    if root is None:
      return BSTNode(key, value)

    if key < root.key:
      root.left = self.insert(root.left, key, value)

    elif key > root.key:
      root.right = self.insert(root.right, key, value)

    else:
      root.value = value

    return root


  def search(self, root, key):

    if root is None:
      return None

    if key == root.key:
      return root.value

    if key < root.key:
      return self.search(root.left, key)

    return self.search(root.right, key)


  def find_min(self, node):
    while node.left is not None:
      node = node.left
    return node


  def delete(self, root, key):

    if root is None:
      return None

    if key < root.key:
      root.left = self.delete(root.left, key)

    elif key > root.key:
      root.right = self.delete(root.right, key)

    else:
      if root.left is None:
        return root.right

      if root.right is None:
        return root.left

      temp = self.find_min(root.right)
      root.key = temp.key
      root.value = temp.value
      root.right = self.delete(root.right, temp.key)

    return root


  def inorder(self, root):

    if root is None:
      return []

    return self.inorder(root.left) + [(root.key, root.value)] + self.inorder(root.right)


  # 핵심: next 연결 함수
  def link_nodes(self, root):

    if root is None:
      return

    nodes = []
    node_map = {}

    # 모든 노드 수집
    def collect(node):
      if node is None:
        return
      collect(node.left)
      nodes.append(node)
      collect(node.right)

    collect(root)

    # next 연결
    for i in range(len(nodes)-1):
      nodes[i].next = nodes[i+1]

    if nodes:
      nodes[-1].next = None

class BSTChainingHashTable(BaseHashTable):

  def __init__(self, size=7):
    super().__init__(size)
    self.bst = BST()


  def hash_fn(self, key):
    return key % self.size


  def insert(self, key, value):

    if self.load_factor() > 0.7:
      print("\n*** REHASH 발생 ***")

      # rehash 전에 next 연결
      for root in self.table:
        if root is not None:
          self.bst.link_nodes(root)

      self.rehash()

    idx = self.hash_fn(key)

    self.table[idx] = self.bst.insert(self.table[idx], key, value)

    # 삽입 후 next 다시 연결
    self.bst.link_nodes(self.table[idx])

    self.count += 1


  def search(self, key):

    idx = self.hash_fn(key)
    return self.bst.search(self.table[idx], key)


  def delete(self, key):

    idx = self.hash_fn(key)

    if self.search(key) is None:
      print("delete FAIL: key not found")
      return

    self.table[idx] = self.bst.delete(self.table[idx], key)

    # 삭제 후 next 재연결
    if self.table[idx] is not None:
      self.bst.link_nodes(self.table[idx])

    self.count -= 1
    print(f"{key} deleted")


  def display(self):

    print("\n[ 해시 테이블 상태 ]")

    for i, root in enumerate(self.table):

      if root is None:
        print(f"[{i}] None")

      else:
        nodes = self.bst.inorder(root)
        print(f"[{i}] {nodes}")

    print()

