def count_islands_DFS(grid):
    if not grid:
        return 0

    m, n = len(grid), len(grid[0])
    count = 0

    def dfs(x, y):
        if x < 0 or x >= m or y < 0 or y >= n or grid[x][y] == 0:
            return

        grid[x][y] = 0  # 방문 처리

        # 상하좌우 탐색
        dfs(x+1, y)
        dfs(x-1, y)
        dfs(x, y+1)
        dfs(x, y-1)

    for i in range(m):
        for j in range(n):
            if grid[i][j] == 1:
                dfs(i, j)
                count += 1

    return count

