def solution(number, k):

    stack = []

    initial_k = k

    steps = []

    print(f"입력 숫자: {number}, 제거할 개수: {k}")

    print("-" * 40)

    for i, num in enumerate(number):

        # 제거 과정
        while stack and k > 0 and stack[-1] < num:

            removed = stack.pop()

            k -= 1

            print(
                f"[제거] {removed} < {num} | "
                f"남은 제거 횟수: {k} | "
                f"현재 스택: {''.join(stack)}"
            )

            steps.append({
                "type": "remove",
                "current": num,
                "removed": removed,
                "stack": stack.copy(),
                "k": k
            })

        # 추가
        stack.append(num)

        print(f"[추가] {num} 삽입 | 현재 스택: {''.join(stack)}")

        steps.append({
            "type": "add",
            "current": num,
            "stack": stack.copy(),
            "k": k
        })

    # 남은 제거 처리
    if k > 0:

        print(f"\n[예외] 제거 횟수가 {k}번 남았습니다. 뒤에서 잘라냅니다.")

        stack = stack[:-k]

        steps.append({
            "type": "trim",
            "stack": stack.copy(),
            "k": 0
        })

    result = "".join(stack)

    print("-" * 40)

    print(f"최종 결과: {result}")

    # HTML 생성
    generate_html(number, initial_k, result, steps)

    return result


