def backtrack(dp, s1, s2, i, j):
    if i == 0 or j == 0:
        return {""}

    current = dp[i][j]

    result = set()

    # 위쪽과 값이 같으면 위쪽 탐색
    if dp[i - 1][j] == current:
        result.update(
            backtrack(dp, s1, s2, i - 1, j)
        )

    # 왼쪽과 값이 같으면 왼쪽 탐색
    if dp[i][j - 1] == current:
        result.update(
            backtrack(dp, s1, s2, i, j - 1)
        )

    # 위쪽, 왼쪽 모두 현재 값과 다르면
    # 문자가 일치한 경우이므로 대각선 이동
    if (
        dp[i - 1][j] != current
        and dp[i][j - 1] != current
    ):
        for lcs in backtrack(
            dp, s1, s2,
            i - 1, j - 1
        ):
            result.add(lcs + s1[i - 1])

    return result


